// figma-import-login.js
// ログイン画面を Figma に追加します。

(async () => {
  const IMG_LOGIN = "data:image/png;base64,";

  // 01_ログイン
  const frame = figma.createFrame();
  frame.name = "01_ログイン";
  frame.resize(1440, 900);
  frame.x = 0;
  frame.y = 0;
  const imgData_login = IMG_LOGIN.replace(/^data:image\/png;base64,/, "");
  const bytes_login = Uint8Array.from(atob(imgData_login), c => c.charCodeAt(0));
  const img_login = figma.createImage(bytes_login);
  frame.fills = [{ type: "IMAGE", scaleMode: "FILL", imageHash: img_login.hash }];

  figma.currentPage.selection = [frame];
  figma.viewport.scrollAndZoomIntoView([frame]);
  figma.closePlugin("✅ 01_ログイン をFigmaに追加しました！");
})();
